  if haveKey=0 {draw_sprite_ext(sMMMapPlacer,image_index,mapMainX+tKeyX,mapMainY+tKeyY,0.5,0.5,0,c_orange,1)}
}
else if vaultMaze[3]="1"
{
  draw_rectangle(timerMainX+3,mapMainY+35,timerMainX+12,mapMainY+44,1)
  draw_set_alpha(0.35)
