else if vaultMaze[3]="9" {draw_rectangle(timerMainX+3,mapMainY+35,timerMainX+12,mapMainY+44,0)}
draw_set_alpha(1)
//------------------------------ Draw player position ------------------------------
playerMapX=mapMainX+tPX+round(oPlayer1.x/39)
playerMapY=mapMainY+tPY+round(oPlayer1.y/39)
